      out.write("        style=\"background-image: url('https://images.unsplash.com/photo-1602216056096-3b40cc0c9944?auto=format&fit=crop&w=1920&q=80')\">\n");
      out.write("    </div>\n");
      out.write("    <div class=\"bg-slide\" data-index=\"2\"\n");
      out.write("        style=\"background-image: url('https://images.unsplash.com/photo-1599661046289-e31897846e41?auto=format&fit=crop&w=1920&q=80')\">\n");
      out.write("    </div>\n");
