      out.write("                    <script>\r\n");
      out.write("                        // Booking Mini Map Setup\r\n");
      out.write("                        function initMiniMap() {\r\n");
      out.write("                            if (typeof google === 'undefined') return;\r\n");
      out.write("\r\n");
      out.write("                            // Custom darkish map styling\r\n");
      out.write("                            const customMapStyle = [\r\n");
      out.write("                                { elementType: \"geometry\", stylers: [{ color: \"#242f3e\" }] },\r\n");
      out.write("                                { elementType: \"labels.text.stroke\", stylers: [{ color: \"#242f3e\" }] },\r\n");
      out.write("                                { elementType: \"labels.text.fill\", stylers: [{ color: \"#746855\" }] },\r\n");
      out.write("                                { featureType: \"water\", elementType: \"geometry\", stylers: [{ color: \"#17263c\" }] },\r\n");
      out.write("                                { featureType: \"road\", elementType: \"geometry\", stylers: [{ color: \"#38414e\" }] }\r\n");
      out.write("                            ];\r\n");
      out.write("\r\n");
      out.write("                            const map = new google.maps.Map(document.getElementById(\"bookingMiniMap\"), {\r\n");
      out.write("                                zoom: 4,\r\n");
      out.write("                                center: { lat: 20.5937, lng: 78.9629 }, // India Map Center\r\n");
      out.write("                                disableDefaultUI: true,\r\n");
      out.write("                                styles: document.documentElement.getAttribute('data-theme') === 'dark' ? customMapStyle : []\r\n");
      out.write("                            });\r\n");
      out.write("\r\n");
      out.write("                            const dirServ = new google.maps.DirectionsService();\r\n");
      out.write("                            const dirRen = new google.maps.DirectionsRenderer({\r\n");
      out.write("                                map: map,\r\n");
      out.write("                                suppressMarkers: false,\r\n");
      out.write("                                polylineOptions: { strokeColor: '#d4a574', strokeWeight: 4 }\r\n");
      out.write("                            });\r\n");
      out.write("\r\n");
      out.write("                            dirServ.route({\r\n");
      out.write("                                origin: \"New Delhi, India\",\r\n");
      out.write("                                destination: \"Mumbai, India\",\r\n");
      out.write("                                travelMode: google.maps.TravelMode.DRIVING\r\n");
      out.write("                            }, (resp, stat) => {\r\n");
      out.write("                                if (stat === \"OK\") {\r\n");
      out.write("                                    dirRen.setDirections(resp);\r\n");
      out.write("                                    document.getElementById('miniMapDist').innerText = resp.routes[0].legs[0].distance.text;\r\n");
      out.write("                                }\r\n");
      out.write("                            });\r\n");
      out.write("                        }\r\n");
      out.write("                        // Request the centralized script to load Google Maps and call initMiniMap when ready\r\n");
      out.write("                        window.addEventListener('DOMContentLoaded', () => {\r\n");
      out.write("                            if (typeof loadGoogleMaps === 'function') {\r\n");
      out.write("                                loadGoogleMaps('initMiniMap');\r\n");
      out.write("                            }\r\n");
      out.write("                        });\r\n");
      out.write("                    </script>\r\n");
      out.write("\r\n");
